use std::fmt::{self, Display};
use std::marker::PhantomData;

struct Unit<T> {
    data: T,
}

impl<T> Unit<T> {
    fn new(data: T) -> Self {
        Unit { data }
    }
}

#[derive(Debug)]
struct XCoord<T> {
    _marker: PhantomData<T>,
}

impl<T> XCoord<T> {
    fn new(val: T) -> Self {
        XCoord { _marker: PhantomData }
    }
}

#[derive(Debug)]
struct YCoord<T> {
    _marker: PhantomData<T>,
}

impl<T> YCoord<T> {
    fn new(val: T) -> Self {
        YCoord { _marker: PhantomData }
    }
}

impl<T> Display for Unit<T> {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "Unit value")
    }
}

fn main() {
    let x_pos = XCoord::<i32>::new(10);
    let y_pos = YCoord::<i32>::new(5);

    println!("X position initialized: {:?}", x_pos);
    println!("Y position initialized: {:?}", y_pos);

    let final_x = i32::from(1) * 2;
    let result_unit = Unit::new(final_x);

    println!("Result unit value: {}", result_unit);
}
